# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import os
import pymysql

def lambda_handler(event, context):
    try:
        # Database connection details from environment variables
        db_host = os.environ.get('DB_HOST')
        db_user = os.environ.get('DB_USER')
        db_password = os.environ.get('DB_PASSWORD')
        db_name = os.environ.get('DB_NAME')
        db_port = int(os.environ.get('DB_PORT', 3306))

        if not all([db_host, db_user, db_password, db_name]):
            raise ValueError("Missing one or more database environment variables.")

        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            port=db_port,
            cursorclass=pymysql.cursors.DictCursor
        )

        cursor = connection.cursor()

        # Parse search parameters from the event body
        # Assuming the event 'body' contains a JSON string of parameters
        if 'body' in event and event['body']:
            try:
                search_params = json.loads(event['body'])
            except json.JSONDecodeError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Invalid JSON in request body'})
                }
        else:
            search_params = {} # No search parameters provided

        # Base query
        sql_query = "SELECT * FROM products WHERE 1=1"
        query_params = []

        # Dynamically build WHERE clause based on search_params
        # Example parameters: 'name', 'category', 'min_price', 'max_price'
        if 'name' in search_params and search_params['name']:
            sql_query += " AND product_name LIKE %s"
            query_params.append(f"%{search_params['name']}%")

        if 'category' in search_params and search_params['category']:
            sql_query += " AND category = %s"
            query_params.append(search_params['category'])

        if 'min_price' in search_params and search_params['min_price'] is not None:
            try:
                min_price = float(search_params['min_price'])
                sql_query += " AND price >= %s"
                query_params.append(min_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Invalid min_price value'})
                }

        if 'max_price' in search_params and search_params['max_price'] is not None:
            try:
                max_price = float(search_params['max_price'])
                sql_query += " AND price <= %s"
                query_params.append(max_price)
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Invalid max_price value'})
                }

        # Add pagination (optional)
        page_size = 10
        page_number = 1
        if 'page_size' in search_params and search_params['page_size'] is not None:
            try:
                page_size = int(search_params['page_size'])
                if page_size <= 0:
                    raise ValueError
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Invalid page_size value'})
                }

        if 'page_number' in search_params and search_params['page_number'] is not None:
            try:
                page_number = int(search_params['page_number'])
                if page_number <= 0:
                    raise ValueError
            except ValueError:
                return {
                    'statusCode': 400,
                    'headers': {'Content-Type': 'application/json'},
                    'body': json.dumps({'error': 'Invalid page_number value'})
                }

        offset = (page_number - 1) * page_size
        sql_query += " LIMIT %s OFFSET %s"
        query_params.append(page_size)
        query_params.append(offset)

        cursor.execute(sql_query, tuple(query_params))
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps(products)
        }

    except pymysql.MySQLError as e:
        print(f"Database error: {e}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Database error', 'details': str(e)})
        }
    except ValueError as e:
        print(f"Configuration error: {e}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Configuration error', 'details': str(e)})
        }
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return {
            'statusCode': 500,
            'headers': {'Content-Type': 'application/json'},
            'body': json.dumps({'error': 'Internal server error', 'details': str(e)})
        }
    finally:
        if 'connection' in locals() and connection.open:
            connection.close()